import{_ as a,o as e,c as r,a0 as n}from"./chunks/framework.CSK6mTG2.js";const u=JSON.parse('{"title":"2025年AI大模型高频面试题之 Transformer（含详细答案解析）","description":"","frontmatter":{"title":"2025年AI大模型高频面试题之 Transformer（含详细答案解析）","author":"唐超","date":"2026-07-06"},"headers":[],"relativePath":"menuAI/transformer-interview.md","filePath":"menuAI/transformer-interview.md"}'),o={name:"menuAI/transformer-interview.md"};function s(d,t,i,l,h,p){return e(),r("div",null,[...t[0]||(t[0]=[n(`<h1 id="_2025年ai大模型高频面试题之-transformer-含详细答案解析" tabindex="-1">2025年AI大模型高频面试题之 Transformer（含详细答案解析） <a class="header-anchor" href="#_2025年ai大模型高频面试题之-transformer-含详细答案解析" aria-label="Permalink to &quot;2025年AI大模型高频面试题之 Transformer（含详细答案解析）&quot;">​</a></h1><blockquote><p>这篇文章梳理了 15 道 Transformer 高频面试题，附上详细答案。不是死记硬背，是把每个知识点从&quot;会背&quot;变成&quot;真懂&quot;。适合准备 AI 算法面试的前端开发者查漏补缺。</p></blockquote><hr><h2 id="一、先画个整体认知-transformer-有哪几块" tabindex="-1">一、先画个整体认知：Transformer 有哪几块？ <a class="header-anchor" href="#一、先画个整体认知-transformer-有哪几块" aria-label="Permalink to &quot;一、先画个整体认知：Transformer 有哪几块？&quot;">​</a></h2><p>在说面试题之前，先把 Transformer 的骨架理清楚。整体分三块：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌────────────────┐     ┌────────────────┐</span></span>
<span class="line"><span>│    Encoder      │────▶│    Decoder     │</span></span>
<span class="line"><span>│  (编码器堆叠×6) │     │  (解码器堆叠×6) │</span></span>
<span class="line"><span>└────────────────┘     └────────────────┘</span></span>
<span class="line"><span>        │                     ▲</span></span>
<span class="line"><span>        │              ┌───────┴───────┐</span></span>
<span class="line"><span>        │              │  交叉注意力层   │</span></span>
<span class="line"><span>        │              │ (Cross-Attention)│</span></span>
<span class="line"><span>        │              └───────────────┘</span></span></code></pre></div><p><strong>Encoder 核心组成（每层）：</strong></p><ul><li>Multi-Head Self-Attention（多头自注意力）</li><li>Feed-Forward Network（全连接前馈网络）</li><li>每个子层都有 <strong>残差连接 + Layer Norm</strong></li></ul><p><strong>Decoder 核心组成（每层）：</strong></p><ul><li>Masked Multi-Head Self-Attention（带掩码的自注意力）</li><li>Cross-Attention（交叉注意力，接 Encoder 输出）</li><li>Feed-Forward Network</li></ul><blockquote><p>记住这个结构，很多面试题都是从这里&quot;挖&quot;出来的。</p></blockquote><hr><h2 id="二、self-attention-计算公式-必背" tabindex="-1">二、Self-Attention 计算公式（必背） <a class="header-anchor" href="#二、self-attention-计算公式-必背" aria-label="Permalink to &quot;二、Self-Attention 计算公式（必背）&quot;">​</a></h2><p>面试官最爱让你&quot;手推&quot;这个公式：</p><p>$$ \\text{Attention}(Q, K, V) = \\text{softmax}\\left(\\frac{QK^T}{\\sqrt{d_k}}\\right)V $$</p><p><strong>三个步骤拆解：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Step 1: QK^T     → 计算&quot;每个词对每个词&quot;的相似度得分</span></span>
<span class="line"><span>Step 2: ÷ √d_k   → 缩放，防止点积过大导致梯度消失</span></span>
<span class="line"><span>Step 3: softmax  → 归一化成概率分布（注意力权重）</span></span>
<span class="line"><span>Step 4: × V      → 加权求和，得到最终输出</span></span></code></pre></div><blockquote><p>如果面试官追问：&quot;为什么偏偏用 <code>√d_k</code> 缩放？&quot; <strong>答：</strong> 当 <code>d_k</code> 较大时，<code>QK^T</code> 的点积值会很大，softmax 会被推入饱和区（梯度接近 0），导致训练困难。<code>√d_k</code> 相当于把方差拉回 1，保证梯度稳定。</p></blockquote><hr><h2 id="三、transformer-优缺点-理解大于背诵" tabindex="-1">三、Transformer 优缺点（理解大于背诵） <a class="header-anchor" href="#三、transformer-优缺点-理解大于背诵" aria-label="Permalink to &quot;三、Transformer 优缺点（理解大于背诵）&quot;">​</a></h2><h3 id="优点" tabindex="-1">优点 <a class="header-anchor" href="#优点" aria-label="Permalink to &quot;优点&quot;">​</a></h3><table tabindex="0"><thead><tr><th>优点</th><th>说明</th></tr></thead><tbody><tr><td><strong>并行能力强</strong></td><td>不像 RNN 必须&quot;一步步&quot;处理，Transformer 可以一次性看完整个序列，训练效率大幅提升</td></tr><tr><td><strong>长距离依赖</strong></td><td>任意两个词之间&quot;一步直达&quot;，不再有 RNN 的梯度消失问题</td></tr><tr><td><strong>灵活性和泛化能力</strong></td><td>一个架构通吃翻译、生成、分类、语音</td></tr><tr><td><strong>可扩展性强</strong></td><td>加层数、加维度、加头数，都能继续涨点</td></tr><tr><td><strong>性能领先</strong></td><td>BLEU、GLUE 等基准上刷新了历史记录</td></tr></tbody></table><h3 id="缺点" tabindex="-1">缺点 <a class="header-anchor" href="#缺点" aria-label="Permalink to &quot;缺点&quot;">​</a></h3><table tabindex="0"><thead><tr><th>缺点</th><th>说明</th></tr></thead><tbody><tr><td><strong>计算资源密集</strong></td><td>自注意力的计算量是 <strong>O(n²)</strong>，长序列直接爆显存</td></tr><tr><td><strong>可解释性差</strong></td><td>注意力权重只是一个参考，模型内部决策过程仍是黑箱</td></tr><tr><td><strong>过拟合风险</strong></td><td>参数量巨大，少量数据容易&quot;背答案&quot;</td></tr><tr><td><strong>训练调参复杂</strong></td><td>学习率、层数、头数、维度……最优组合需要大量实验</td></tr><tr><td><strong>局部信息捕获弱</strong></td><td>全局 attention 反而对&quot;相邻词&quot;关系不如 CNN/RNN 敏感</td></tr><tr><td><strong>长序列挑战</strong></td><td>非常长的文本（&gt; 32K tokens）性能会明显下降</td></tr></tbody></table><blockquote><p>面试加分项：主动说&quot;针对这些缺点业界有哪些优化方案&quot;（如 Sparse Attention、FlashAttention、Ring Attention 等）。</p></blockquote><hr><h2 id="四、encoder-和-decoder-怎么-对话" tabindex="-1">四、Encoder 和 Decoder 怎么&quot;对话&quot;？ <a class="header-anchor" href="#四、encoder-和-decoder-怎么-对话" aria-label="Permalink to &quot;四、Encoder 和 Decoder 怎么&quot;对话&quot;？&quot;">​</a></h2><p>Encoder 编码输入，Decoder 生成输出，两者通过 <strong>Cross-Attention（交叉注意力）</strong> 连接。</p><p><strong>交互流程：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Encoder 处理输入序列，输出每个词的上下文表示（K 和 V）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. Decoder 在生成第 t 个词时：</span></span>
<span class="line"><span>   - Query：来自 Decoder 自身（当前要生成的词）</span></span>
<span class="line"><span>   - Key &amp; Value：来自 Encoder 的输出（整个输入序列的上下文）</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>3. Cross-Attention 计算：</span></span>
<span class="line"><span>   Attention(Q_decoder, K_encoder, V_encoder)</span></span>
<span class="line"><span>   → Decoder 在生成时&quot;参考&quot;了整个输入序列的信息</span></span></code></pre></div><p><strong>一个比喻：</strong></p><blockquote><p>翻译任务是 Encoder-Decoder 交互的经典场景。Encoder 像是一个&quot;阅读理解者&quot;，把原文读完后标注好重点；Decoder 在翻译时，随时回头查这个&quot;阅读理解者&quot;的笔记，决定下一个词怎么写。</p></blockquote><hr><h2 id="五、q-k-v-为什么要做线性变换" tabindex="-1">五、Q/K/V 为什么要做线性变换？ <a class="header-anchor" href="#五、q-k-v-为什么要做线性变换" aria-label="Permalink to &quot;五、Q/K/V 为什么要做线性变换？&quot;">​</a></h2><p><strong>核心原因：增加表达能力的&quot;泛化半径&quot;。</strong></p><p>没有线性变换时，Q、K、V 就是原始输入的直接投影，学到的关系是&quot;固定的&quot;。 加了 <code>W_q</code>、<code>W_k</code>、<code>W_v</code> 三个参数矩阵后：</p><ul><li>Q 和 K 被投影到<strong>不同的子空间</strong>，可以从不同角度衡量相似度</li><li>这和 SVM 用核函数把向量映射到高维空间是同样思想——<strong>用非线性变换捕获更复杂的模式</strong></li></ul><hr><h2 id="六、为什么注意力矩阵用乘法而不是加法" tabindex="-1">六、为什么注意力矩阵用乘法而不是加法？ <a class="header-anchor" href="#六、为什么注意力矩阵用乘法而不是加法" aria-label="Permalink to &quot;六、为什么注意力矩阵用乘法而不是加法？&quot;">​</a></h2><p><strong>答案：计算速度 + 硬件友好。</strong></p><table tabindex="0"><thead><tr><th>操作</th><th>特点</th></tr></thead><tbody><tr><td>矩阵乘法</td><td>有高度成熟的 GPU/TPU 加速实现（cuBLAS 等），利用率高</td></tr><tr><td>加法 + 激活</td><td>虽然数学上等价，但无法利用并行硬件加速</td></tr></tbody></table><p>实践中，<code>QK^T</code> 的矩阵乘法可以一次并行算出所有词的注意力分数，速度远快于逐元素加法。</p><hr><h2 id="七、padding-mask-怎么做" tabindex="-1">七、Padding Mask 怎么做？ <a class="header-anchor" href="#七、padding-mask-怎么做" aria-label="Permalink to &quot;七、Padding Mask 怎么做？&quot;">​</a></h2><p><strong>目的：</strong> 输入序列长度不一，需要 padding 补齐，但模型不该关注这些&quot;补进来的无意义词&quot;。</p><p><strong>操作：</strong></p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 在 QK^T 之后、softmax 之前</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">attention_scores </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> attention_scores.masked_fill(mask </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1e9</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># padding 位置的分数设为极小值，softmax 后概率接近 0</span></span></code></pre></div><p>等价于：把这些位置乘以一个&quot;忽略权重&quot;，让模型根本&quot;不看&quot;它们。</p><hr><h2 id="八、残差连接的意义-重点理解" tabindex="-1">八、残差连接的意义（重点理解） <a class="header-anchor" href="#八、残差连接的意义-重点理解" aria-label="Permalink to &quot;八、残差连接的意义（重点理解）&quot;">​</a></h2><h3 id="结构公式" tabindex="-1">结构公式 <a class="header-anchor" href="#结构公式" aria-label="Permalink to &quot;结构公式&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Output = LayerNorm(x + Sublayer(x))</span></span></code></pre></div><h3 id="五个核心意义" tabindex="-1">五个核心意义 <a class="header-anchor" href="#五个核心意义" aria-label="Permalink to &quot;五个核心意义&quot;">​</a></h3><table tabindex="0"><thead><tr><th>意义</th><th>解释</th></tr></thead><tbody><tr><td><strong>缓解梯度消失</strong></td><td>梯度可以绕过子层直接传回输入层</td></tr><tr><td><strong>加速收敛</strong></td><td>底层梯度更稳定，学习更高效</td></tr><tr><td><strong>促进深层训练</strong></td><td>残差通道让信息在深层网络中&quot;抄近道&quot;</td></tr><tr><td><strong>保留原始信息</strong></td><td>即使堆了 12 层，底层特征也不会被覆盖</td></tr><tr><td><strong>支持特征重用</strong></td><td>低层特征可直接被高层引用，不需要重新学习</td></tr></tbody></table><blockquote><p><strong>面试高频追问：</strong>&quot;残差连接为什么有效？&quot; <strong>标准答案：</strong> 因为它提供了&quot;恒等映射&quot;这条通道。网络学习的目标从&quot;直接拟合底层到顶层的复杂函数&quot;，变成了&quot;拟合残差&quot;。当残差接近 0 时，深层网络至少能退化成浅层网络，性能不会退化。</p></blockquote><hr><h2 id="九、为什么用-layer-norm-而不是-batch-norm" tabindex="-1">九、为什么用 Layer Norm 而不是 Batch Norm？ <a class="header-anchor" href="#九、为什么用-layer-norm-而不是-batch-norm" aria-label="Permalink to &quot;九、为什么用 Layer Norm 而不是 Batch Norm？&quot;">​</a></h2><p><strong>一句话答案：</strong> Batch Norm 依赖 batch 内统计量，NLP 任务 batch 大小往往很小且序列长度不一致，LN 更稳定。</p><table tabindex="0"><thead><tr><th>对比</th><th>Layer Norm</th><th>Batch Norm</th></tr></thead><tbody><tr><td>归一化方向</td><td>对单个样本的所有特征</td><td>对 batch 内所有样本的同一特征</td></tr><tr><td>序列任务</td><td>✅ 稳定</td><td>❌ 不稳定（序列长度不一致时问题大）</td></tr><tr><td>RNN / Transformer</td><td>✅ 常用</td><td>❌ 基本不用</td></tr><tr><td>训练/推理一致性</td><td>✅ 一样</td><td>❌ 不一样（batch 统计量在推理时要用移动平均）</td></tr></tbody></table><blockquote><p>在 Transformer 中，每个样本的每个位置都有自己的归一化参数，不受 batch 影响，所以 LN 是标准配置。</p></blockquote><hr><h2 id="十、decoder-的自注意力和-encoder-有什么区别" tabindex="-1">十、Decoder 的自注意力和 Encoder 有什么区别？ <a class="header-anchor" href="#十、decoder-的自注意力和-encoder-有什么区别" aria-label="Permalink to &quot;十、Decoder 的自注意力和 Encoder 有什么区别？&quot;">​</a></h2><p><strong>本质区别：Decoder 有 causal mask（因果掩码）。</strong></p><h3 id="encoder-多头注意力" tabindex="-1">Encoder 多头注意力 <a class="header-anchor" href="#encoder-多头注意力" aria-label="Permalink to &quot;Encoder 多头注意力&quot;">​</a></h3><ul><li><strong>无掩码</strong>，每个词可以&quot;看&quot;序列中的所有其他词</li><li>双向上下文</li></ul><h3 id="decoder-多头注意力-分两层" tabindex="-1">Decoder 多头注意力（分两层） <a class="header-anchor" href="#decoder-多头注意力-分两层" aria-label="Permalink to &quot;Decoder 多头注意力（分两层）&quot;">​</a></h3><p><strong>第一层：Masked Self-Attention</strong></p><ul><li>加了 causal mask，生成第 <code>t</code> 个词时<strong>只能看到前 t-1 个词</strong></li><li>保证<strong>自回归特性</strong>：模型在预测当前词时，不会&quot;偷看&quot;答案</li><li>这是 <strong>并行训练</strong> 的关键——用 mask 模拟串行依赖</li></ul><p><strong>第二层：Cross-Attention（与 Encoder 交互）</strong></p><ul><li>Query 来自 Decoder 自身</li><li>Key 和 Value 来自 Encoder 最终输出</li></ul><hr><h2 id="十一、decoder-能并行化吗" tabindex="-1">十一、Decoder 能并行化吗？ <a class="header-anchor" href="#十一、decoder-能并行化吗" aria-label="Permalink to &quot;十一、Decoder 能并行化吗？&quot;">​</a></h2><p><strong>训练时：可以并行。</strong> 靠的就是 causal mask，把&quot;不能看的词&quot;屏蔽掉，整个序列可以一起算。</p><p><strong>推理时：不行，必须逐词生成。</strong> 因为第 <code>t</code> 个词的输入依赖第 <code>t-1</code> 个词的输出，这是序列依赖，无法并行。</p><blockquote><p><strong>面试加分项：</strong> 解释清楚&quot;训练并行 vs 推理不并行&quot;的根本原因。</p></blockquote><hr><h2 id="十二、计算量最大的部分是哪里" tabindex="-1">十二、计算量最大的部分是哪里？ <a class="header-anchor" href="#十二、计算量最大的部分是哪里" aria-label="Permalink to &quot;十二、计算量最大的部分是哪里？&quot;">​</a></h2><p><strong>答案：多头自注意力机制。</strong></p><p>复杂度分析：</p><table tabindex="0"><thead><tr><th>部分</th><th>时间复杂度</th><th>空间复杂度</th></tr></thead><tbody><tr><td>Self-Attention</td><td><strong>O(n² · d)</strong></td><td>O(n²) 存储注意力矩阵</td></tr><tr><td>Feed-Forward</td><td>O(n · d²)</td><td>O(n · d²)</td></tr><tr><td>多头</td><td>× h（头数）</td><td>× h</td></tr></tbody></table><ul><li><code>n</code> = 序列长度</li><li><code>d</code> = 模型维度</li><li><code>h</code> = 头数</li></ul><blockquote><p><code>n²</code> 是瓶颈！当序列长度翻倍，计算量涨 4 倍。这就是为什么长上下文是工程难题。</p></blockquote><hr><h2 id="十三、transformer-vs-lstm-vs-纯-ffn-提升在哪里" tabindex="-1">十三、Transformer vs LSTM vs 纯 FFN，提升在哪里？ <a class="header-anchor" href="#十三、transformer-vs-lstm-vs-纯-ffn-提升在哪里" aria-label="Permalink to &quot;十三、Transformer vs LSTM vs 纯 FFN，提升在哪里？&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模型</th><th>能力</th></tr></thead><tbody><tr><td>纯 FFN</td><td>无顺序感知，词序信息完全丢失</td></tr><tr><td>LSTM</td><td>理解语序，解决梯度消失/爆炸</td></tr><tr><td><strong>Transformer</strong></td><td>一步到位解决长距离依赖 + 并行训练</td></tr></tbody></table><p><strong>核心进化链：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>FFN（无序）→ LSTM（理解顺序，解决短距离依赖）</span></span>
<span class="line"><span>→ Transformer（全序列可见，解决长距离依赖，可并行）</span></span></code></pre></div><hr><h2 id="十四、面试最容易被问到的-5-道追问" tabindex="-1">十四、面试最容易被问到的 5 道追问 <a class="header-anchor" href="#十四、面试最容易被问到的-5-道追问" aria-label="Permalink to &quot;十四、面试最容易被问到的 5 道追问&quot;">​</a></h2><h3 id="q1-为什么-multi-head-不用一个头" tabindex="-1">Q1：为什么 Multi-Head 不用一个头？ <a class="header-anchor" href="#q1-为什么-multi-head-不用一个头" aria-label="Permalink to &quot;Q1：为什么 Multi-Head 不用一个头？&quot;">​</a></h3><p><strong>A：</strong> 多个头能让模型在不同的子空间学习不同的注意力模式，有的头关注语法关系，有的头关注语义相似度……矩阵总维度不变，但表达能力更强。</p><h3 id="q2-残差连接为什么加在每个子层而不是只在特定位置" tabindex="-1">Q2：残差连接为什么加在每个子层而不是只在特定位置？ <a class="header-anchor" href="#q2-残差连接为什么加在每个子层而不是只在特定位置" aria-label="Permalink to &quot;Q2：残差连接为什么加在每个子层而不是只在特定位置？&quot;">​</a></h3><p><strong>A：</strong> 每个子层都有信息损失和梯度风险，均匀加残差保证每一层都能直接获得原始信号，避免&quot;哪一层塌了&quot;都不知道。</p><h3 id="q3-attention-计算时-q、k、v-能不能用同一个矩阵" tabindex="-1">Q3：Attention 计算时 Q、K、V 能不能用同一个矩阵？ <a class="header-anchor" href="#q3-attention-计算时-q、k、v-能不能用同一个矩阵" aria-label="Permalink to &quot;Q3：Attention 计算时 Q、K、V 能不能用同一个矩阵？&quot;">​</a></h3><p><strong>A：</strong> 可以，但效果差。用同一个矩阵，Q 和 K 被投影到同一空间，学到的相似度模式单一；分开投影让模型从更多角度衡量相关性。</p><h3 id="q4-transformer-对超长文本怎么处理" tabindex="-1">Q4：Transformer 对超长文本怎么处理？ <a class="header-anchor" href="#q4-transformer-对超长文本怎么处理" aria-label="Permalink to &quot;Q4：Transformer 对超长文本怎么处理？&quot;">​</a></h3><p><strong>A：</strong> 常用方法：Sparse Attention（稀疏注意力）、FlashAttention（IO感知的精确注意力）、Ring Attention（分布式长上下文）、滑动窗口 + 全局注意力的分层策略。</p><h3 id="q5-如果让你优化-transformer-的推理速度-你会怎么做" tabindex="-1">Q5：如果让你优化 Transformer 的推理速度，你会怎么做？ <a class="header-anchor" href="#q5-如果让你优化-transformer-的推理速度-你会怎么做" aria-label="Permalink to &quot;Q5：如果让你优化 Transformer 的推理速度，你会怎么做？&quot;">​</a></h3><p><strong>A：</strong> KV Cache 缓存已计算结果 + 避免重复计算、量化（INT8/INT4）减小内存带宽压力、投机解码（Speculative Decoding）小模型猜、大模型验证、剪枝不重要的注意力头。</p><hr><h2 id="写在最后" tabindex="-1">写在最后 <a class="header-anchor" href="#写在最后" aria-label="Permalink to &quot;写在最后&quot;">​</a></h2><p>Transformer 的面试题看似零散，但始终围绕几条主线：</p><ul><li><strong>架构理解</strong>：Encoder/Decoder 各层组成及作用</li><li><strong>Attention 本质</strong>：Q/K/V 的数学含义、Mask 的作用</li><li><strong>工程难点</strong>：O(n²) 计算量、长序列、显存瓶颈</li><li><strong>对比思维</strong>：Transformer vs RNN/LSTM 的本质区别</li></ul><p>把主线理清，追问再多也能接住。</p>`,104)])])}const g=a(o,[["render",s]]);export{u as __pageData,g as default};
